import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  // Simplest case
  it.todo("should return empty array when input is empty -- []");

  // Single cell dies example
  it.todo("should kill a single live cell with 0 neighbors (single cell dies example) -- [(0,0)] -> []");

  // Rule 1 - Underpopulation example: two horizontal cells each with 1 neighbor die
  it.todo("should kill both cells when two adjacent cells each have only 1 neighbor (Rule 1 underpopulation) -- [(0,1),(1,1)] -> []");

  // Rule 2 - Survival example: center (1,1) with 3 neighbors survives
  it.todo("should keep center cell alive when it has 3 live neighbors (Rule 2 survival) -- center (1,1) in [(0,2),(1,2),(2,2),(1,0)] survives");

  // Rule 3 - Overpopulation example: center (1,1) with 4 neighbors dies
  it.todo("should kill center cell when it has 4 live neighbors (Rule 3 overpopulation) -- center (1,1) in [(0,2),(1,2),(2,2),(1,1),(0,0),(1,0),(2,0)] dies");

  // Rule 4 - Reproduction example: dead cell (1,1) with exactly 3 neighbors becomes alive
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (Rule 4 reproduction) -- [(0,2),(1,2),(0,1)] produces (1,1) alive");

  // Block still life pattern
  it.todo("should keep a 2x2 block unchanged (Block still life) -- [(0,0),(1,0),(0,1),(1,1)] -> same");

  // Blinker pattern - vertical to horizontal
  it.todo("should oscillate vertical blinker to horizontal (Blinker Gen0->Gen1) -- [(0,0),(0,1),(0,2)] -> [(-1,1),(0,1),(1,1)]");

  // Blinker pattern - horizontal back to vertical
  it.todo("should oscillate horizontal blinker back to vertical (Blinker Gen1->Gen2) -- [(-1,1),(0,1),(1,1)] -> [(0,0),(0,1),(0,2)]");

  // Negative coordinates support
  it.todo("should handle negative coordinates correctly -- blinker at negative coords works");
});

