  const isAlive = (x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);

  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (isAlive(x + dx, y + dy)) count++;
      }
    }
    return count;
  };

  const survivors: Cell[] = cells.filter(([x, y]) => {
    const n = countNeighbors(x, y);
    return n === 2 || n === 3;
  });

  // Collect candidate dead neighbors of live cells
  const candidateKeys = new Set<string>();
  const candidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        if (isAlive(nx, ny)) continue;
        const key = `${nx},${ny}`;
        if (candidateKeys.has(key)) continue;
        candidateKeys.add(key);
        candidates.push([nx, ny]);
      }
    }
  }

  const births: Cell[] = candidates.filter(([x, y]) => countNeighbors(x, y) === 3);

  return [...survivors, ...births];
}

